<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Admin\Content\ContentAdminReadService;use App\Domain\Admin\Content\ContentAdminService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\LootEntryRequest;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use InvalidArgumentException;
final class LootController extends Controller{public function index(ContentAdminReadService $read){return view('admin.content.loot.index',['entries'=>$read->loot(),'read'=>$read]);}public function store(LootEntryRequest $request,Monster $monster,ContentAdminService $service){try{$item=Item::findOrFail($request->validated()['item_id']);$service->saveLoot($monster,$item,$request->validated());return redirect()->route('admin.content.monsters.show',$monster)->with('status','Loot agregado.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function update(LootEntryRequest $request,Monster $monster,MonsterLootEntry $lootEntry,ContentAdminService $service){try{if((int)$lootEntry->monster_id!==(int)$monster->id)abort(404);$item=Item::findOrFail($request->validated()['item_id']);$service->saveLoot($monster,$item,$request->validated(),$lootEntry);return redirect()->route('admin.content.monsters.show',$monster)->with('status','Loot actualizado correctamente.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function activate(Monster $monster,MonsterLootEntry $lootEntry,ContentAdminService $service){try{if((int)$lootEntry->monster_id!==(int)$monster->id)abort(404);$service->activateLoot($monster,$lootEntry);return redirect()->route('admin.content.monsters.show',$monster)->with('status','Loot activado correctamente.');}catch(InvalidArgumentException $e){return back()->withErrors(['content'=>$e->getMessage()]);}}public function deactivate(Monster $monster,MonsterLootEntry $lootEntry,ContentAdminService $service){if((int)$lootEntry->monster_id!==(int)$monster->id)abort(404);$service->deactivateLoot($monster,$lootEntry);return redirect()->route('admin.content.monsters.show',$monster)->with('status','Loot desactivado correctamente.');}}
